// Detect whether this item came from an Etsy search or the KDP Claude research node.
// Etsy API responses have a 'results' array.
// KDP node (Claude API) responses have a 'content' array.
var isEtsy = $json.results !== undefined;
var isKdp  = !isEtsy && $json.content && Array.isArray($json.content);

var items = [];

if (isEtsy) {
  items = ($json.results || []).slice(0, 25).map(function(l) {
    return {
      source: 'etsy',
      title: l.title,
      price_usd: l.price ? (l.price.amount / (l.price.divisor || 100)) : 0,
      num_reviews: l.num_reviews || 0,
      tags: (l.tags || []).slice(0, 8)
    };
  });

} else if (isKdp) {
  var rawText = ($json.content[0] || {}).text || '';
  // Strip web-search tool_use blocks — Claude may return multiple content blocks;
  // find the text block that contains the JSON array.
  if ($json.content.length > 1) {
    for (var i = 0; i < $json.content.length; i++) {
      if ($json.content[i].type === 'text') {
        rawText = $json.content[i].text || '';
        break;
      }
    }
  }
  var cleanText = rawText.trim().startsWith('```')
    ? rawText.trim().replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '').trim()
    : rawText.trim();
  try {
    var kdpData = JSON.parse(cleanText);
    if (Array.isArray(kdpData)) {
      items = kdpData.map(function(item) {
        return {
          source: 'kdp',
          title: item.title_pattern || item.title || 'Unknown KDP Topic',
          competition: item.competition_level || 'unknown',
          price_range: item.price_range || '',
          niche_hint: 'ebook_guide'
        };
      });
    }
  } catch(e) {
    // KDP node returned unparseable content — skip this item
    return [];
  }
}

if (items.length === 0) {
  return [];
}

// Build the Claude Haiku scoring request body using array.join to avoid
// any double-quote characters in the JS source (prevents JSON escaping bugs).
var systemLines = [
  'You score digital product opportunities for Cipher Studio.',
  'Products sold: spreadsheet templates, Notion templates, business documents, printable planners, educational printables, and ebooks for freelancers and small business owners.',
  '',
  'Score each item 1-10 on four dimensions:',
  '- demand: market demand signals (reviews, search volume, KDP competition signals)',
  '- competition: inverse score (10 = low competition, 1 = highly saturated)',
  '- margin: profit potential based on price point and bundle potential',
  '- ai_producibility: how easily AI can create high-quality output for this product',
  '',
  'EBOOK SCORING GUIDANCE:',
  '- Prioritise specificity of topic (niche beats broad)',
  '- Favour cross-sell potential alongside existing Cipher Studio templates',
  '- Prioritise topics where AI can produce high-quality long-form content',
  '- Single ebooks: target $9.99-19.99 price range',
  '- Ebook + template bundles: target $29-49 price range',
  '- Low-competition KDP niches with specific actionable how-to angles score highest',
  '',
  'Return ONLY a valid JSON array. No markdown fences, no prose outside the array.',
  'Only include items where (demand + competition + margin + ai_producibility) >= 30.',
  '',
  'Each array element must have these exact fields:',
  '  title (string),',
  '  niche (one of: spreadsheet_templates | notion_templates | business_documents | printable_planners | educational_printables | ebook_guide | ebook_bundle),',
  '  etsy_search (string — search term that surfaced this opportunity),',
  '  keywords (array of strings),',
  '  score (decimal — sum of four scores divided by 4, rounded to 2dp),',
  '  rationale (string — one sentence),',
  '  score_demand (integer 1-10),',
  '  score_competition (integer 1-10),',
  '  score_margin (integer 1-10),',
  '  score_ai_producibility (integer 1-10)'
];

var requestBody = JSON.stringify({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  system: systemLines.join('\n'),
  messages: [{
    role: 'user',
    content: 'Score these opportunities and return qualifying items as a JSON array:\n\n' + JSON.stringify(items, null, 2)
  }]
});

return [{ json: { requestBody: requestBody, itemCount: items.length, source: isEtsy ? 'etsy' : 'kdp' } }];
